-- ─── spBuildSalesReport (Level 1 — THE BIG ONE, ~150 lines) ────────────────
-- TotalRevenue = Qty * UnitPrice (COMPUTED COLUMN SPLIT)
-- AdjustedRevenue = TotalRevenue - Discount
-- CustomerSegment from CustomerSegmentMap (dead end for revenue)
-- RegionLookup for Region name (dead end for revenue)
-- Multi-step: #SalesBase → UPDATE with prices → final INSERT
CREATE PROCEDURE [ai].[spBuildSalesReport]
    @ReportDate       DATE          = NULL,
    @RegionFilter     VARCHAR(10)   = NULL,    -- NULL = all regions
    @FiscalYearOverride INT         = NULL,    -- NULL = current fiscal year
    @IncludeZeroQty   BIT           = 0,       -- include zero-qty rows in report
    @RebuildMode      VARCHAR(10)   = 'APPEND',-- APPEND / FULL / DELTA
    @DryRun           BIT           = 0,
    @DebugLevel       INT           = 0        -- 0=off, 1=basic, 2=verbose
AS
BEGIN
    /*
    ════════════════════════════════════════════════════════════════════════════════
    spBuildSalesReport — Master report builder for FactSalesReport
    ════════════════════════════════════════════════════════════════════════════════
    VERSION HISTORY:
    ────────────────
    v1.0 (2023-Q4) Initial version — single query, no temp tables
    v1.1 (2024-Q1) Added CustomerSegment enrichment from CustomerMaster
    v1.2 (2024-Q2) Split TotalRevenue into Qty * UnitPrice for auditability
                   (Previously was a pre-computed column from SalesStaging)
    v2.0 (2024-Q3) Major refactor: multi-step temp table approach
                   - Added #SalesBase, #PriceEnriched, #SegmentEnriched
                   - Added RegionLookup for display names
                   - Added vwDiscountCalc for discount computation
    v2.1 (2024-Q4) Added @RebuildMode parameter (APPEND/FULL/DELTA)
    v3.0 (2025-Q1) Performance: removed intermediate #PriceEnriched table
                   Now updates #SalesBase in-place
    v3.1 (2025-Q2) Added concurrency control with sp_getapplock
    v3.2 (2025-Q3) Added @DebugLevel, @DryRun parameters
    v4.0 (2025-Q4) Added fiscal year override and region filter
    v4.1 (2026-Q1) Fixed NULL handling in CustomerSegment CASE expression
                   (Bug #4821: anonymous orders getting 'Unclassified' instead of 'Anonymous')
    COLUMN FLOW:
    ────────────
    The key revenue columns flow through this SP as follows:
    - Qty: vwConsolidatedSales.Qty → #SalesBase.Qty → FactSalesReport.Qty
    - UnitPrice: vwPriceList.UnitPrice → #SalesBase.UnitPrice → FactSalesReport.UnitPrice
    - TotalRevenue: computed as Qty * UnitPrice in the final INSERT
    - Discount: vwDiscountCalc.Discount → #SalesBase.Discount → FactSalesReport.Discount
    - AdjustedRevenue: computed as TotalRevenue - Discount in the final INSERT
    - CustomerSegment: CustomerSegmentMap.SegmentName → #SalesBase.CustomerSegment
      (NOT part of revenue calculation — enrichment only)
    - Region: RegionLookup.RegionName → #SalesBase.RegionName
      (NOT part of revenue calculation — display only)
    DEPENDENCIES:
    ─────────────
    READ:  ai.vwConsolidatedSales, ai.vwPriceList, ai.vwDiscountCalc,
           ai.CustomerMaster, ai.CustomerSegmentMap, ai.RegionLookup
    WRITE: ai.FactSalesReport, ai.ErrorLog
    EXEC:  ai.spLogAudit
    PERMISSIONS REQUIRED:
    ─────────────────────
    SELECT on all read dependencies
    INSERT/DELETE on ai.FactSalesReport
    INSERT on ai.ErrorLog
    EXECUTE on ai.spLogAudit
    ESTIMATED RUNTIME:
    ──────────────────
    ~2-5 seconds for 10K rows, ~30-60 seconds for 500K rows
    Bottleneck is Step 2 (price lookup) due to vwPriceList CTE complexity
    ════════════════════════════════════════════════════════════════════════════════
    */
    SET NOCOUNT ON;
    SET XACT_ABORT OFF;
    -- ═══════════════════════════════════════════════════════════════════════
    -- PARAMETER INITIALIZATION AND VALIDATION
    -- ═══════════════════════════════════════════════════════════════════════
    IF @ReportDate IS NULL
        SET @ReportDate = CAST(GETDATE() AS DATE);
    IF @RebuildMode NOT IN ('APPEND', 'FULL', 'DELTA')
    BEGIN
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage)
        VALUES ('spBuildSalesReport.Validate', 50010,
            'Invalid @RebuildMode: ' + ISNULL(@RebuildMode, 'NULL'));
        RETURN;
    END;
    DECLARE @StartTime     DATETIME2 = SYSUTCDATETIME();
    DECLARE @StepStart     DATETIME2;
    DECLARE @InsertedRows   INT = 0;
    DECLARE @StepRowCount  INT = 0;
    DECLARE @WarningCount  INT = 0;
    DECLARE @ErrorCount    INT = 0;
    DECLARE @DeletedRows   INT = 0;
    DECLARE @StatusMsg     NVARCHAR(MAX) = N'';
    DECLARE @CurrentStep   VARCHAR(50);
    DECLARE @FiscalYear    INT = ISNULL(@FiscalYearOverride, YEAR(GETDATE()));
    -- Acquire advisory lock to prevent concurrent builds
    DECLARE @LockResult INT;
    EXEC @LockResult = sp_getapplock
        @Resource   = 'spBuildSalesReport_Lock',
        @LockMode   = 'Exclusive',
        @LockOwner  = 'Session',
        @LockTimeout = 30000;
    IF @LockResult < 0
    BEGIN
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage)
        VALUES ('spBuildSalesReport.Lock', 50011,
            'Could not acquire lock. Another build may be running. Result=' + CAST(@LockResult AS VARCHAR));
        RETURN;
    END;
    -- Debug output
    IF @DebugLevel >= 1
    BEGIN
        DECLARE @DebugMsg NVARCHAR(MAX) = CONCAT(
            N'[spBuildSalesReport] Starting build. Parameters: ',
            N'ReportDate=', FORMAT(@ReportDate, 'yyyy-MM-dd'),
            N', Region=', ISNULL(@RegionFilter, 'ALL'),
            N', FiscalYear=', @FiscalYear,
            N', Mode=', @RebuildMode,
            N', DryRun=', @DryRun,
            N', Debug=', @DebugLevel
        );
        RAISERROR(@DebugMsg, 0, 1) WITH NOWAIT;
    END;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 0: Handle rebuild modes
    -- FULL = delete existing data for this report date and rebuild
    -- DELTA = only process new staging rows since last build
    -- APPEND = add new rows (default)
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step0_RebuildMode';
    IF @RebuildMode = 'FULL'
    BEGIN
        DELETE FROM [ai].[FactSalesReport]
        WHERE ReportDate = @ReportDate
          AND (@RegionFilter IS NULL OR RegionCode = @RegionFilter);
        SET @DeletedRows = @@ROWCOUNT;
        SET @StatusMsg = @StatusMsg + CONCAT(N'FULL rebuild: deleted ', @DeletedRows, N' existing rows. ');
        IF @DebugLevel >= 1
            RAISERROR('[Step0] Deleted %d existing rows for FULL rebuild', 0, 1, @DeletedRows) WITH NOWAIT;
    END;
    /* ═══════════════════════════════════════════════════════════════════════
       DELTA MODE IMPLEMENTATION (partially implemented, deferred to v5.0)
       The idea was to track which staging rows have already been processed
       using a watermark table. This would avoid re-processing rows that
       are already in FactSalesReport.
       CREATE TABLE [ai].[BuildWatermark] (
           RegionCode VARCHAR(10),
           LastStagingID BIGINT,
           LastBuildDate DATETIME2,
           PRIMARY KEY (RegionCode)
       );
       IF @RebuildMode = 'DELTA'
       BEGIN
           -- Get watermark
           SELECT @LastStagingID = ISNULL(MAX(LastStagingID), 0)
           FROM [ai].[BuildWatermark]
           WHERE @RegionFilter IS NULL OR RegionCode = @RegionFilter;
           -- Only process rows newer than watermark
           -- WHERE cs.StagingID > @LastStagingID
       END;
    ═══════════════════════════════════════════════════════════════════════ */
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 1: Build base sales data from consolidated view into #SalesBase
    -- The Qty column flows from vwConsolidatedSales (which renames OrderQty to Qty)
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step1_Extract';
    SET @StepStart = SYSUTCDATETIME();
    BEGIN TRY
        SELECT
            cs.StagingID,
            cs.Qty,
            cs.OrderAmount,
            cs.RegionCode,
            cs.OrderDate,
            cs.CustomerID,
            cs.CustomerName,
            CAST(NULL AS DECIMAL(18,4))   AS UnitPrice,
            CAST(NULL AS DECIMAL(18,2))   AS Discount,
            CAST(NULL AS VARCHAR(50))     AS CustomerSegment,
            CAST(NULL AS NVARCHAR(100))   AS RegionName,
            CAST(0 AS BIT)               AS IsProcessed,
            CAST(0 AS BIT)               AS HasPriceMatch,
            CAST(0 AS BIT)               AS HasSegmentMatch,
            CAST(NULL AS NVARCHAR(500))   AS ProcessingNotes
        INTO #SalesBase
        FROM [ai].[vwConsolidatedSales] cs
        WHERE (@RegionFilter IS NULL OR cs.RegionCode = @RegionFilter);
        SET @StepRowCount = @@ROWCOUNT;
        IF @DebugLevel >= 1
            RAISERROR('[Step1] Extracted %d rows from vwConsolidatedSales', 0, 1, @StepRowCount) WITH NOWAIT;
        IF @StepRowCount = 0
        BEGIN
            SET @StatusMsg = @StatusMsg + N'No data in vwConsolidatedSales for given filters. ';
            SET @WarningCount = @WarningCount + 1;
            -- Don't return — still log the empty run
        END;
    END TRY
    BEGIN CATCH
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage, ErrorLine)
        VALUES ('spBuildSalesReport.Step1', ERROR_NUMBER(), ERROR_MESSAGE(), ERROR_LINE());
        SET @ErrorCount = @ErrorCount + 1;
        GOTO Cleanup;
    END CATCH;
    -- Create index on temp table for performance
    CREATE NONCLUSTERED INDEX IX_SalesBase_Region ON #SalesBase (RegionCode);
    CREATE NONCLUSTERED INDEX IX_SalesBase_Customer ON #SalesBase (CustomerID) WHERE CustomerID IS NOT NULL;
    CREATE NONCLUSTERED INDEX IX_SalesBase_Staging ON #SalesBase (StagingID);
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 2: Enrich with UnitPrice from price list
    -- UnitPrice comes from vwPriceList (which is a 3-CTE rename chain:
    --   PriceMaster.ListPrice → BasePrice → AdjPrice → UnitPrice)
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step2_PriceEnrich';
    SET @StepStart = SYSUTCDATETIME();
    /* Old approach v1 (pre-2024-Q2):
       SELECT TotalRevenue FROM ai.SalesStaging
       This pulled a pre-computed TotalRevenue. Removed when we split into
       Qty * UnitPrice for better auditability and drill-down capability.
       UPDATE #SalesBase SET UnitPrice = s.TotalRevenue / NULLIF(s.OrderQty, 0)
       FROM ai.SalesStaging s WHERE s.StagingID = #SalesBase.StagingID
    */
    /* Old approach v2 (2024-Q2 to 2025-Q1):
       Used a separate #PriceEnriched temp table and JOIN:
       SELECT sb.*, pl.UnitPrice
       INTO #PriceEnriched
       FROM #SalesBase sb
       LEFT JOIN [ai].[vwPriceList] pl ON sb.RegionCode = pl.RegionCode;
       DROP TABLE #SalesBase;
       SELECT * INTO #SalesBase FROM #PriceEnriched;
       DROP TABLE #PriceEnriched;
       Removed in v3.0 for simplification — now updates in-place.
    */
    -- v1 used hardcoded price of 9.99 here (removed 2025-Q1)
    -- v2 used per-product pricing (removed when ProductCode was dropped from staging)
    -- v3 (current): region-level pricing from vwPriceList
    BEGIN TRY
        UPDATE sb
        SET sb.UnitPrice = COALESCE(pl.UnitPrice, 0),
            sb.HasPriceMatch = CASE WHEN pl.UnitPrice IS NOT NULL THEN 1 ELSE 0 END,
            sb.ProcessingNotes = CASE
                WHEN pl.UnitPrice IS NULL THEN 'No price match for region ' + sb.RegionCode
                WHEN pl.UnitPrice = 0 THEN 'Zero price for region ' + sb.RegionCode
                ELSE NULL
            END
        FROM #SalesBase sb
        LEFT JOIN [ai].[vwPriceList] pl
            ON sb.RegionCode = pl.RegionCode;
        -- NOTE: ProductCode join removed in simplification — uses region-level price
        -- NOTE: EffectiveFrom date filter would go here if we had date-specific pricing
        SET @StepRowCount = @@ROWCOUNT;
        -- Count rows without price matches (warning condition)
        DECLARE @NoPriceCount INT;
        SELECT @NoPriceCount = COUNT(*) FROM #SalesBase WHERE HasPriceMatch = 0;
        IF @NoPriceCount > 0
        BEGIN
            SET @WarningCount = @WarningCount + 1;
            SET @StatusMsg = @StatusMsg + CONCAT(N'Warning: ', @NoPriceCount, N' rows have no price match. ');
        END;
        IF @DebugLevel >= 1
            RAISERROR('[Step2] Price enrichment: %d rows updated, %d without price', 0, 1, @StepRowCount, @NoPriceCount) WITH NOWAIT;
        IF @DebugLevel >= 2
        BEGIN
            -- Verbose: show price distribution
            SELECT
                RegionCode,
                COUNT(*) AS [RowCount],
                MIN(UnitPrice) AS MinPrice,
                MAX(UnitPrice) AS MaxPrice,
                AVG(UnitPrice) AS AvgPrice,
                SUM(CASE WHEN HasPriceMatch = 0 THEN 1 ELSE 0 END) AS NoPriceRows
            FROM #SalesBase
            GROUP BY RegionCode;
        END;
    END TRY
    BEGIN CATCH
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage, ErrorLine)
        VALUES ('spBuildSalesReport.Step2', ERROR_NUMBER(), ERROR_MESSAGE(), ERROR_LINE());
        SET @ErrorCount = @ErrorCount + 1;
    END CATCH;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 3: Enrich with Discount from discount calc view
    -- Discount comes from vwDiscountCalc (multi-CTE rename chain:
    --   OrderAmount → BaseAmt → DiscountVal → Discount)
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step3_DiscountEnrich';
    SET @StepStart = SYSUTCDATETIME();
    BEGIN TRY
        UPDATE sb
        SET sb.Discount = COALESCE(dc.Discount, 0)
        FROM #SalesBase sb
        LEFT JOIN [ai].[vwDiscountCalc] dc
            ON sb.StagingID = dc.StagingID;
        SET @StepRowCount = @@ROWCOUNT;
        IF @DebugLevel >= 1
            RAISERROR('[Step3] Discount enrichment: %d rows updated', 0, 1, @StepRowCount) WITH NOWAIT;
    END TRY
    BEGIN CATCH
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage, ErrorLine)
        VALUES ('spBuildSalesReport.Step3', ERROR_NUMBER(), ERROR_MESSAGE(), ERROR_LINE());
        -- Non-fatal: continue with Discount = 0
        SET @WarningCount = @WarningCount + 1;
        SET @StatusMsg = @StatusMsg + N'Discount enrichment failed; using 0. ';
    END CATCH;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 4: Enrich with CustomerSegment (dead end for revenue trace)
    -- CustomerSegmentMap is NOT in the revenue computation path.
    -- This only populates the CustomerSegment display column.
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step4_SegmentEnrich';
    SET @StepStart = SYSUTCDATETIME();
    BEGIN TRY
        UPDATE sb
        SET sb.CustomerSegment = csm.SegmentName,
            sb.HasSegmentMatch = CASE WHEN csm.SegmentName IS NOT NULL THEN 1 ELSE 0 END
        FROM #SalesBase sb
        INNER JOIN [ai].[CustomerMaster] cm
            ON sb.CustomerID = cm.CustomerID
        LEFT JOIN [ai].[CustomerSegmentMap] csm
            ON cm.CustomerTier = csm.CustomerTier
           AND cm.RegionCode   = csm.RegionCode;
        SET @StepRowCount = @@ROWCOUNT;
        /* Old segment logic (pre v2.0):
           Used a direct CASE expression instead of CustomerSegmentMap:
           UPDATE sb SET sb.CustomerSegment = CASE
               WHEN cm.AnnualSpend > 100000 THEN 'Enterprise'
               WHEN cm.AnnualSpend > 10000  THEN 'Mid-Market'
               WHEN cm.AnnualSpend > 1000   THEN 'SMB'
               ELSE 'Consumer'
           END
           FROM #SalesBase sb JOIN ai.CustomerMaster cm ON sb.CustomerID = cm.CustomerID
           Removed because AnnualSpend column was deprecated in CustomerMaster.
        */
        IF @DebugLevel >= 1
            RAISERROR('[Step4] Segment enrichment: %d rows matched', 0, 1, @StepRowCount) WITH NOWAIT;
        IF @DebugLevel >= 2
        BEGIN
            -- Verbose: segment distribution
            SELECT
                COALESCE(CustomerSegment, '(none)') AS Segment,
                COUNT(*) AS [RowCount],
                SUM(Qty) AS TotalQty,
                SUM(CAST(Qty AS DECIMAL(18,2)) * UnitPrice) AS EstRevenue
            FROM #SalesBase
            GROUP BY CustomerSegment;
        END;
    END TRY
    BEGIN CATCH
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage, ErrorLine)
        VALUES ('spBuildSalesReport.Step4', ERROR_NUMBER(), ERROR_MESSAGE(), ERROR_LINE());
        -- Non-fatal
        SET @WarningCount = @WarningCount + 1;
    END CATCH;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 5: Enrich with Region name (dead end for revenue trace)
    -- RegionLookup provides display name only, NOT revenue data
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step5_RegionEnrich';
    SET @StepStart = SYSUTCDATETIME();
    BEGIN TRY
        UPDATE sb
        SET sb.RegionName = rl.RegionName
        FROM #SalesBase sb
        LEFT JOIN [ai].[RegionLookup] rl
            ON sb.RegionCode = rl.RegionCode;
        SET @StepRowCount = @@ROWCOUNT;
        -- Fill in missing region names with code
        UPDATE #SalesBase
        SET RegionName = RegionCode
        WHERE RegionName IS NULL;
        IF @DebugLevel >= 1
            RAISERROR('[Step5] Region enrichment: %d rows updated', 0, 1, @StepRowCount) WITH NOWAIT;
    END TRY
    BEGIN CATCH
        -- Non-fatal: use RegionCode as fallback
        UPDATE #SalesBase SET RegionName = RegionCode WHERE RegionName IS NULL;
        SET @WarningCount = @WarningCount + 1;
    END CATCH;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 6: Pre-insert validation and quality checks
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step6_PreInsertValidation';
    -- 6a: Check for NULL Qty (should never happen, but defensive)
    DECLARE @NullQtyCount INT;
    SELECT @NullQtyCount = COUNT(*) FROM #SalesBase WHERE Qty IS NULL;
    IF @NullQtyCount > 0
    BEGIN
        UPDATE #SalesBase SET Qty = 0 WHERE Qty IS NULL;
        SET @WarningCount = @WarningCount + 1;
        SET @StatusMsg = @StatusMsg + CONCAT(N'Fixed ', @NullQtyCount, N' NULL Qty rows. ');
    END;
    -- 6b: Check for NULL UnitPrice
    DECLARE @NullPriceCount INT;
    SELECT @NullPriceCount = COUNT(*) FROM #SalesBase WHERE UnitPrice IS NULL;
    IF @NullPriceCount > 0
    BEGIN
        UPDATE #SalesBase SET UnitPrice = 0 WHERE UnitPrice IS NULL;
        SET @WarningCount = @WarningCount + 1;
        SET @StatusMsg = @StatusMsg + CONCAT(N'Fixed ', @NullPriceCount, N' NULL UnitPrice rows. ');
    END;
    -- 6c: Check for negative values (data quality anomaly)
    DECLARE @NegativeQty INT, @NegativePrice INT;
    SELECT @NegativeQty = COUNT(*) FROM #SalesBase WHERE Qty < 0;
    SELECT @NegativePrice = COUNT(*) FROM #SalesBase WHERE UnitPrice < 0;
    IF @NegativeQty > 0 OR @NegativePrice > 0
    BEGIN
        SET @WarningCount = @WarningCount + 1;
        SET @StatusMsg = @StatusMsg + CONCAT(N'Negative values: Qty=', @NegativeQty, N', Price=', @NegativePrice, N'. ');
    END;
    -- 6d: Check for suspicious outliers (revenue > 1M per row)
    DECLARE @OutlierCount INT;
    SELECT @OutlierCount = COUNT(*)
    FROM #SalesBase
    WHERE CAST(Qty AS DECIMAL(18,2)) * UnitPrice > 1000000;
    IF @OutlierCount > 0
    BEGIN
        SET @WarningCount = @WarningCount + 1;
        SET @StatusMsg = @StatusMsg + CONCAT(N'Outlier rows (revenue>1M): ', @OutlierCount, N'. ');
        -- Log outlier details for investigation
        IF @DebugLevel >= 2
        BEGIN
            SELECT TOP 10
                StagingID, RegionCode, Qty, UnitPrice,
                CAST(Qty AS DECIMAL(18,2)) * UnitPrice AS EstRevenue,
                'OUTLIER' AS Flag
            FROM #SalesBase
            WHERE CAST(Qty AS DECIMAL(18,2)) * UnitPrice > 1000000
            ORDER BY CAST(Qty AS DECIMAL(18,2)) * UnitPrice DESC;
        END;
    END;
    -- 6e: Mark all valid rows as processed
    UPDATE #SalesBase
    SET IsProcessed = 1
    WHERE (@IncludeZeroQty = 1 OR Qty > 0)
      AND UnitPrice >= 0;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 7: Compute summary statistics BEFORE insert (for reporting)
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step7_PreInsertStats';
    DECLARE @PreInsertStats TABLE (
        RegionCode  VARCHAR(10),
        [RowCount]  INT,
        TotalQty    BIGINT,
        TotalRevenue DECIMAL(18,2),
        AvgPrice    DECIMAL(18,4),
        MinPrice    DECIMAL(18,4),
        MaxPrice    DECIMAL(18,4)
    );
    INSERT INTO @PreInsertStats
    SELECT
        RegionCode,
        COUNT(*),
        SUM(CAST(Qty AS BIGINT)),
        SUM(CAST(Qty AS DECIMAL(18,2)) * UnitPrice),
        AVG(UnitPrice),
        MIN(UnitPrice),
        MAX(UnitPrice)
    FROM #SalesBase
    WHERE IsProcessed = 1
    GROUP BY RegionCode;
    IF @DebugLevel >= 2
        SELECT * FROM @PreInsertStats ORDER BY RegionCode;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 8: Final INSERT into FactSalesReport
    -- ═══════════════════════════════════════════════════════════════════════
    --  TotalRevenue    = Qty * UnitPrice     <== THIS IS THE KEY COMPUTATION
    --  AdjustedRevenue = (Qty * UnitPrice) - Discount
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step8_Insert';
    SET @StepStart = SYSUTCDATETIME();
    IF @DryRun = 1
    BEGIN
        -- Dry run: show what WOULD be inserted
        SELECT
            'DRY_RUN' AS Mode,
            COUNT(*) AS WouldInsertRows,
            SUM(CAST(sb.Qty AS DECIMAL(18,2)) * sb.UnitPrice) AS WouldInsertRevenue,
            MIN(sb.OrderDate) AS MinDate,
            MAX(sb.OrderDate) AS MaxDate,
            COUNT(DISTINCT sb.RegionCode) AS DistinctRegions
        FROM #SalesBase sb
        WHERE sb.IsProcessed = 1;
        SET @InsertedRows = 0;
        SET @StatusMsg = @StatusMsg + N'DRY RUN — no data inserted. ';
    END
    ELSE
    BEGIN
        BEGIN TRY
            INSERT INTO [ai].[FactSalesReport]
                (ReportDate, Region, RegionCode, CustomerSegment,
                 Qty, UnitPrice, TotalRevenue, Discount, AdjustedRevenue, OrderDate)
            SELECT
                @ReportDate,
                COALESCE(sb.RegionName, sb.RegionCode),
                sb.RegionCode,
                CASE
                    WHEN sb.CustomerSegment IS NOT NULL THEN sb.CustomerSegment
                    WHEN sb.CustomerID IS NOT NULL      THEN 'Unclassified'
                    ELSE 'Anonymous'
                END,
                sb.Qty,
                sb.UnitPrice,
                sb.Qty * sb.UnitPrice                                AS TotalRevenue,
                sb.Discount,
                (sb.Qty * sb.UnitPrice) - COALESCE(sb.Discount, 0)  AS AdjustedRevenue,
                sb.OrderDate
            FROM #SalesBase sb
            WHERE sb.IsProcessed = 1;
            SET @InsertedRows = @@ROWCOUNT;
            IF @DebugLevel >= 1
                RAISERROR('[Step8] Inserted %d rows into FactSalesReport', 0, 1, @InsertedRows) WITH NOWAIT;
        END TRY
        BEGIN CATCH
            INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage, ErrorLine)
            VALUES ('spBuildSalesReport.Step8', ERROR_NUMBER(), ERROR_MESSAGE(), ERROR_LINE());
            SET @ErrorCount = @ErrorCount + 1;
            GOTO Cleanup;
        END CATCH;
    END;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 9: Post-insert verification
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step9_PostVerify';
    IF @DryRun = 0 AND @InsertedRows > 0
    BEGIN
        -- Verify row count in target matches what we inserted
        DECLARE @VerifyCount INT;
        SELECT @VerifyCount = COUNT(*)
        FROM [ai].[FactSalesReport]
        WHERE ReportDate = @ReportDate
          AND (@RegionFilter IS NULL OR RegionCode = @RegionFilter)
          AND CreatedAt >= @StartTime;
        IF @VerifyCount <> @InsertedRows
        BEGIN
            SET @WarningCount = @WarningCount + 1;
            SET @StatusMsg = @StatusMsg + CONCAT(
                N'Post-verify mismatch: expected ', @InsertedRows,
                N', found ', @VerifyCount, N'. ');
        END;
        -- Check for negative TotalRevenue (should never happen with Qty>0 and UnitPrice>0)
        DECLARE @NegRevCount INT;
        SELECT @NegRevCount = COUNT(*)
        FROM [ai].[FactSalesReport]
        WHERE ReportDate = @ReportDate
          AND TotalRevenue < 0
          AND CreatedAt >= @StartTime;
        IF @NegRevCount > 0
        BEGIN
            SET @WarningCount = @WarningCount + 1;
            SET @StatusMsg = @StatusMsg + CONCAT(N'Negative TotalRevenue: ', @NegRevCount, N' rows. ');
        END;
        IF @DebugLevel >= 2
        BEGIN
            -- Post-insert summary by region
            SELECT
                RegionCode,
                COUNT(*) AS Rows,
                SUM(TotalRevenue) AS Revenue,
                SUM(AdjustedRevenue) AS AdjRevenue,
                SUM(Discount) AS TotalDiscount
            FROM [ai].[FactSalesReport]
            WHERE ReportDate = @ReportDate AND CreatedAt >= @StartTime
            GROUP BY RegionCode
            ORDER BY SUM(TotalRevenue) DESC;
        END;
    END;
    /* ═══════════════════════════════════════════════════════════════════════
       CROSS-CHECK WITH SOURCE DATA (disabled — too slow for production)
       This used to compare FactSalesReport totals against raw SalesStaging
       totals to detect data loss. Disabled in v3.1 because the cross-check
       itself was taking longer than the build.
       SELECT
           'SalesStaging' AS Source,
           COUNT(*) AS [RowCount],
           SUM(OrderQty) AS TotalQty,
           SUM(OrderAmount) AS TotalAmount
       FROM [ai].[SalesStaging]
       WHERE IsValid = 1
       UNION ALL
       SELECT
           'FactSalesReport',
           COUNT(*),
           SUM(Qty),
           SUM(TotalRevenue)
       FROM [ai].[FactSalesReport]
       WHERE ReportDate = @ReportDate;
    ═══════════════════════════════════════════════════════════════════════ */
    -- ═══════════════════════════════════════════════════════════════════════
    -- CLEANUP: Drop temp tables, release lock, log audit
    -- ═══════════════════════════════════════════════════════════════════════
    Cleanup:
    SET @CurrentStep = 'Cleanup';
    DROP TABLE IF EXISTS #SalesBase;
    DECLARE @Duration INT = DATEDIFF(MILLISECOND, @StartTime, SYSUTCDATETIME());
    DECLARE @AuditMsg NVARCHAR(MAX) = CONCAT(
        N'Report built: ', @InsertedRows, N' rows in ', @Duration, N'ms. ',
        N'Date: ', FORMAT(@ReportDate, 'yyyy-MM-dd'), N'. ',
        N'Mode: ', @RebuildMode, N'. ',
        N'Deleted: ', @DeletedRows, N'. ',
        N'Warnings: ', @WarningCount, N'. ',
        N'Errors: ', @ErrorCount, N'. ',
        @StatusMsg
    );
    EXEC [ai].[spLogAudit]
        @EventType    = 'BUILD',
        @ObjectName   = 'FactSalesReport',
        @AffectedRows = @InsertedRows,
        @Message      = @AuditMsg;
    -- Release advisory lock
    EXEC sp_releaseapplock @Resource = 'spBuildSalesReport_Lock', @LockOwner = 'Session';
    IF @DebugLevel >= 1
        RAISERROR('[Complete] %d rows, %d warnings, %d errors, %dms', 0, 1,
            @InsertedRows, @WarningCount, @ErrorCount, @Duration) WITH NOWAIT;
END;

-- ─── spArchiveOldOrders (dead-end: downstream, reads SalesStaging→ArchiveOrders) ─
CREATE PROCEDURE [ai].[spArchiveOldOrders]
    @CutoffDate DATE = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF @CutoffDate IS NULL
        SET @CutoffDate = DATEADD(YEAR, -2, GETDATE());
    INSERT INTO [ai].[ArchiveOrders] (OrderQty, OrderAmount, RegionCode, OrderDate)
    SELECT OrderQty, OrderAmount, RegionCode, OrderDate
    FROM [ai].[SalesStaging]
    WHERE OrderDate < @CutoffDate;
    DELETE FROM [ai].[SalesStaging]
    WHERE OrderDate < @CutoffDate;
    EXEC [ai].[spLogAudit]
        @EventType  = 'ARCHIVE',
        @ObjectName = 'SalesStaging',
        @AffectedRows = @@ROWCOUNT;
END;

-- ─── spLoadSalesStaging (Level 4 — SELECT * passthrough) ────────────────────
CREATE PROCEDURE [ai].[spLoadSalesStaging]
AS
BEGIN
    SET NOCOUNT ON;
    -- TRUNCATE and reload pattern — SELECT * passes ALL columns through
    TRUNCATE TABLE [ai].[SalesStaging];
    -- SELECT * means every column from vwRawOrders flows through unchanged
    -- This includes OrderQty, OrderAmount, RegionCode, OrderDate, etc.
    -- The view uses SELECT * from CleanedOrders — all columns pass through
    INSERT INTO [ai].[SalesStaging]
        (OrderQty, OrderAmount, RegionCode, OrderDate, CustomerID, CustomerName, IsValid)
    SELECT
        v.OrderQty, v.OrderAmount, v.RegionCode, v.OrderDate,
        v.CustomerID, v.CustomerName, v.IsValid
    FROM [ai].[vwRawOrders] v;
    -- Backfill DateKey for calendar join
    UPDATE s
    SET s.OrderDateKey = dc.DateKey
    FROM [ai].[SalesStaging] s
    INNER JOIN [ai].[DimCalendar] dc
        ON s.OrderDate = dc.FullDate;
    EXEC [ai].[spLogAudit]
        @EventType  = 'LOAD',
        @ObjectName = 'SalesStaging',
        @AffectedRows = @@ROWCOUNT;
END;

-- ─── spImportOrders (Level 9 — large SP ~180 lines, batch bloat) ────────────
-- Renames: ext.Quantity→RawQty, ext.Amount→RawAmount
-- ActiveRegions is a FILTER-ONLY subquery (no data columns)
CREATE PROCEDURE [ai].[spImportOrders]
    @BatchSize       INT = 10000,
    @LookbackDays    INT = 90,
    @DryRun          BIT = 0,
    @ForceReimport   BIT = 0,
    @SourceFilter    VARCHAR(10) = NULL,  -- NULL = all sources, 'SAP', 'Oracle'
    @MaxRetries      INT = 3
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT OFF;  -- we handle errors manually per step
    -- ═══════════════════════════════════════════════════════════════════════
    -- PARAMETER VALIDATION AND INITIALIZATION
    -- ═══════════════════════════════════════════════════════════════════════
    DECLARE @BatchID         INT = NEXT VALUE FOR dbo.BatchSeq;
    DECLARE @TotalRows       INT = 0;
    DECLARE @ProcessedRows   INT = 0;
    DECLARE @ErrorCount      INT = 0;
    DECLARE @WarningCount    INT = 0;
    DECLARE @DuplicateCount  INT = 0;
    DECLARE @NegativeCount   INT = 0;
    DECLARE @StartTime       DATETIME2 = SYSUTCDATETIME();
    DECLARE @StepStart       DATETIME2;
    DECLARE @RetryCount      INT = 0;
    DECLARE @CurrentStep     VARCHAR(50) = 'Init';
    DECLARE @StatusMsg       NVARCHAR(MAX) = N'';
    -- Validate @BatchSize range
    IF @BatchSize < 100 OR @BatchSize > 1000000
    BEGIN
        SET @BatchSize = 10000;
        SET @WarningCount = @WarningCount + 1;
        SET @StatusMsg = @StatusMsg + N'BatchSize out of range, reset to 10000. ';
    END;
    -- Validate @LookbackDays
    IF @LookbackDays < 1 OR @LookbackDays > 365
    BEGIN
        SET @LookbackDays = 90;
        SET @WarningCount = @WarningCount + 1;
        SET @StatusMsg = @StatusMsg + N'LookbackDays out of range, reset to 90. ';
    END;
    -- Validate @SourceFilter
    IF @SourceFilter IS NOT NULL AND @SourceFilter NOT IN ('SAP', 'Oracle')
    BEGIN
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage)
        VALUES ('spImportOrders.Validate', 50001,
            'Invalid @SourceFilter: ' + ISNULL(@SourceFilter, 'NULL') + '. Must be SAP, Oracle, or NULL.');
        RETURN;
    END;
    -- Check for concurrent execution (advisory lock pattern)
    DECLARE @LockResult INT;
    EXEC @LockResult = sp_getapplock
        @Resource = 'spImportOrders_Lock',
        @LockMode = 'Exclusive',
        @LockOwner = 'Session',
        @LockTimeout = 5000;
    IF @LockResult < 0
    BEGIN
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage)
        VALUES ('spImportOrders.Lock', 50002,
            'Could not acquire lock — another instance may be running. LockResult=' + CAST(@LockResult AS VARCHAR));
        RETURN;
    END;
    -- v2: renamed Qty to Quantity here (WRONG COMMENT: it's actually the opposite)
    -- v3: added SourceFilter parameter (2025-Q2)
    -- v4: added retry logic for transient failures (2025-Q3)
    -- SELECT Amount, Price, Discount FROM ai.OldPricing  (commented out, never existed)
    -- SELECT TotalRevenue, GrossAmount FROM ai.FactSalesReport  -- old reconciliation query
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 1: Pull from external orders into temp batch table
    -- The ACTUAL column mapping happens here:
    --   vwExternalOrders.Quantity → #RawBatch.RawQty (RENAME)
    --   vwExternalOrders.Amount   → #RawBatch.RawAmount (RENAME)
    -- ActiveRegions is FILTER ONLY — no data columns flow through
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step1_Extract';
    SET @StepStart = SYSUTCDATETIME();
    DECLARE @ExtractRetry INT = 0;
    WHILE @ExtractRetry <= @MaxRetries
    BEGIN
        BEGIN TRY
            IF OBJECT_ID('tempdb..#RawBatch') IS NOT NULL
                DROP TABLE #RawBatch;
            SELECT
                ext.Quantity     AS RawQty,
                ext.Amount       AS RawAmount,
                ext.RegionCode,
                ext.OrderDate,
                ext.SourceSystem,
                @BatchID         AS BatchID,
                CAST(NULL AS VARCHAR(50)) AS CustomerRef,
                CAST(0 AS BIT)   AS IsValidated,
                CAST(0 AS BIT)   AS IsDuplicate,
                ROW_NUMBER() OVER (
                    PARTITION BY ext.SourceSystem, ext.OrderDate
                    ORDER BY ext.OrderID
                )                AS RowSeq,
                CAST(NULL AS VARCHAR(200)) AS ValidationMessage
            INTO #RawBatch
            FROM [ai].[vwExternalOrders] ext
            -- ActiveRegions: FILTER ONLY — controls which regions we import from
            -- No columns from ActiveRegions flow into RawQty or RawAmount
            WHERE ext.RegionCode IN (
                SELECT ar.RegionCode
                FROM [ai].[ActiveRegions] ar
                WHERE ar.IsActive = 1
            )
            AND ext.OrderDate >= DATEADD(DAY, -@LookbackDays, GETDATE())
            AND (@SourceFilter IS NULL OR ext.SourceSystem = @SourceFilter);
            SET @TotalRows = @@ROWCOUNT;
            BREAK;  -- success, exit retry loop
        END TRY
        BEGIN CATCH
            SET @ExtractRetry = @ExtractRetry + 1;
            IF @ExtractRetry > @MaxRetries
            BEGIN
                INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage, ErrorLine)
                VALUES ('spImportOrders.Step1', ERROR_NUMBER(), ERROR_MESSAGE(), ERROR_LINE());
                EXEC sp_releaseapplock @Resource = 'spImportOrders_Lock', @LockOwner = 'Session';
                RETURN;
            END;
            -- Transient error: wait and retry
            WAITFOR DELAY '00:00:02';
        END CATCH;
    END;
    /* ═══════════════════════════════════════════════════════════════════════
       DIAGNOSTIC: Uncomment this block to dump raw batch for debugging.
       This was used during the SAP→Oracle migration in 2024.
       SELECT TOP 100
           RawQty, RawAmount, RegionCode, OrderDate, SourceSystem,
           'DEBUG_DUMP' AS DebugFlag
       FROM #RawBatch
       ORDER BY OrderDate DESC;
       -- Also tried joining back to check:
       -- SELECT rb.RawQty AS ImportedQty, ext.Quantity AS OriginalQty,
       --        rb.RawAmount AS ImportedAmt, ext.Amount AS OriginalAmt
       -- FROM #RawBatch rb
       -- JOIN [ai].[vwExternalOrders] ext ON rb.OrderDate = ext.OrderDate
       -- WHERE rb.SourceSystem = ext.SourceSystem;
    ═══════════════════════════════════════════════════════════════════════ */
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 2: Data quality validation
    -- These validations modify #RawBatch in-place but do NOT change the
    -- column mapping. RawQty and RawAmount are the data-carrying columns.
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step2_Validate';
    SET @StepStart = SYSUTCDATETIME();
    -- 2a: Remove duplicates within batch (keep first by RowSeq)
    UPDATE #RawBatch
    SET IsDuplicate = 1
    WHERE RowSeq > 1;
    SET @DuplicateCount = @@ROWCOUNT;
    DELETE FROM #RawBatch
    WHERE IsDuplicate = 1;
    -- 2b: Remove rows that already exist in RawOrderImport (dedup against target)
    IF @ForceReimport = 0
    BEGIN
        DELETE rb
        FROM #RawBatch rb
        INNER JOIN [ai].[RawOrderImport] roi
            ON  rb.OrderDate    = roi.OrderDate
            AND rb.RegionCode   = roi.RegionCode
            AND rb.RawQty       = roi.RawQty
            AND rb.RawAmount    = roi.RawAmount
            AND rb.SourceSystem = roi.SourceSystem;
        SET @DuplicateCount = @DuplicateCount + @@ROWCOUNT;
    END;
    -- 2c: Flag negative quantities (data quality)
    UPDATE #RawBatch
    SET RawQty = 0,
        ValidationMessage = COALESCE(ValidationMessage + '; ', '') + 'Negative qty corrected'
    WHERE RawQty < 0;
    SET @NegativeCount = @@ROWCOUNT;
    -- 2d: Flag suspicious amounts (> 10M or < 0)
    UPDATE #RawBatch
    SET ValidationMessage = COALESCE(ValidationMessage + '; ', '') + 'Suspicious amount: ' + CAST(RawAmount AS VARCHAR)
    WHERE RawAmount > 10000000 OR RawAmount < 0;
    SET @WarningCount = @WarningCount + @@ROWCOUNT;
    -- 2e: Validate region codes against ActiveRegions (belt-and-suspenders check)
    UPDATE rb
    SET rb.ValidationMessage = COALESCE(rb.ValidationMessage + '; ', '') + 'Unknown region'
    FROM #RawBatch rb
    WHERE NOT EXISTS (
        SELECT 1 FROM [ai].[ActiveRegions] ar
        WHERE ar.RegionCode = rb.RegionCode AND ar.IsActive = 1
    );
    -- 2f: Mark all surviving rows as validated
    UPDATE #RawBatch
    SET IsValidated = 1
    WHERE ValidationMessage IS NULL OR ValidationMessage NOT LIKE '%Unknown region%';
    /* ═══════════════════════════════════════════════════════════════════════
       OLD BATCH PARTITIONING LOGIC (removed Q4 2025)
       This used to process in chunks of @BatchSize with OFFSET/FETCH.
       Now we just INSERT the whole batch at once since volumes are lower.
       DECLARE @ChunkStart INT = 0;
       WHILE @ChunkStart < @TotalRows
       BEGIN
           INSERT INTO [ai].[RawOrderImport]
               (RawQty, RawAmount, RegionCode, OrderDate, SourceSystem, BatchID)
           SELECT RawQty, RawAmount, RegionCode, OrderDate, SourceSystem, BatchID
           FROM #RawBatch
           WHERE IsValidated = 1
           ORDER BY RowSeq
           OFFSET @ChunkStart ROWS
           FETCH NEXT @BatchSize ROWS ONLY;
           SET @ChunkStart = @ChunkStart + @@ROWCOUNT;
           -- Yield point for long-running batches
           IF @ChunkStart % 50000 = 0
               WAITFOR DELAY '00:00:01';
       END;
       -- v2 considered using BULK INSERT from staging file:
       -- BULK INSERT [ai].[RawOrderImport]
       -- FROM '\\fileserver\imports\raw_orders.csv'
       -- WITH (FIELDTERMINATOR = ',', ROWTERMINATOR = '\n', FIRSTROW = 2);
    ═══════════════════════════════════════════════════════════════════════ */
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 3: Insert validated batch into RawOrderImport
    -- This is the ACTUAL data flow: #RawBatch → RawOrderImport
    -- Only validated, non-duplicate rows are inserted.
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step3_Insert';
    SET @StepStart = SYSUTCDATETIME();
    IF @DryRun = 1
    BEGIN
        -- Dry run: report what WOULD be inserted without committing
        SELECT
            @BatchID AS BatchID,
            COUNT(*) AS WouldInsertRows,
            SUM(CASE WHEN IsValidated = 1 THEN 1 ELSE 0 END) AS ValidRows,
            SUM(CASE WHEN IsValidated = 0 THEN 1 ELSE 0 END) AS InvalidRows,
            MIN(OrderDate) AS MinDate,
            MAX(OrderDate) AS MaxDate,
            COUNT(DISTINCT RegionCode) AS DistinctRegions,
            COUNT(DISTINCT SourceSystem) AS DistinctSources
        FROM #RawBatch;
        SET @ProcessedRows = 0;
    END
    ELSE
    BEGIN
        DECLARE @InsertRetry INT = 0;
        WHILE @InsertRetry <= @MaxRetries
        BEGIN
            BEGIN TRY
                INSERT INTO [ai].[RawOrderImport]
                    (RawQty, RawAmount, RegionCode, OrderDate, SourceSystem, BatchID)
                SELECT
                    rb.RawQty,
                    rb.RawAmount,
                    rb.RegionCode,
                    rb.OrderDate,
                    rb.SourceSystem,
                    rb.BatchID
                FROM #RawBatch rb
                WHERE rb.IsValidated = 1;
                SET @ProcessedRows = @@ROWCOUNT;
                BREAK;  -- success
            END TRY
            BEGIN CATCH
                SET @InsertRetry = @InsertRetry + 1;
                IF @InsertRetry > @MaxRetries
                BEGIN
                    INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage, ErrorLine)
                    VALUES ('spImportOrders.Step3', ERROR_NUMBER(), ERROR_MESSAGE(), ERROR_LINE());
                    SET @ErrorCount = @ErrorCount + 1;
                    BREAK;
                END;
                WAITFOR DELAY '00:00:02';
            END CATCH;
        END;
    END;
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 4: Post-insert statistics and validation
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step4_PostValidate';
    -- Verify row counts match between #RawBatch and RawOrderImport
    DECLARE @VerifyCount INT;
    SELECT @VerifyCount = COUNT(*)
    FROM [ai].[RawOrderImport]
    WHERE BatchID = @BatchID;
    IF @VerifyCount <> @ProcessedRows AND @DryRun = 0
    BEGIN
        SET @WarningCount = @WarningCount + 1;
        SET @StatusMsg = @StatusMsg + N'Row count mismatch: expected '
            + CAST(@ProcessedRows AS NVARCHAR) + N', found '
            + CAST(@VerifyCount AS NVARCHAR) + N'. ';
    END;
    -- Compute batch statistics for monitoring
    DECLARE @BatchStats TABLE (
        Metric VARCHAR(50),
        Value  DECIMAL(18,2)
    );
    INSERT INTO @BatchStats
    SELECT 'AvgQty', AVG(CAST(RawQty AS DECIMAL(18,2))) FROM #RawBatch WHERE IsValidated = 1
    UNION ALL
    SELECT 'MaxQty', MAX(CAST(RawQty AS DECIMAL(18,2))) FROM #RawBatch WHERE IsValidated = 1
    UNION ALL
    SELECT 'AvgAmount', AVG(RawAmount) FROM #RawBatch WHERE IsValidated = 1
    UNION ALL
    SELECT 'MaxAmount', MAX(RawAmount) FROM #RawBatch WHERE IsValidated = 1
    UNION ALL
    SELECT 'TotalAmount', SUM(RawAmount) FROM #RawBatch WHERE IsValidated = 1
    UNION ALL
    SELECT 'Duplicates', @DuplicateCount
    UNION ALL
    SELECT 'NegativeQty', @NegativeCount;
    /* ═══════════════════════════════════════════════════════════════════════
       RECONCILIATION QUERY (for manual verification after import)
       Compares source counts with imported counts.
       SELECT
           src.SourceSystem,
           src.TotalOrders AS SourceCount,
           imp.ImportedOrders AS ImportCount,
           src.TotalOrders - ISNULL(imp.ImportedOrders, 0) AS Delta,
           src.TotalQty AS SourceQty,
           imp.ImportedQty AS ImportQty,
           src.TotalAmount AS SourceAmount,
           imp.ImportedAmount AS ImportAmount
       FROM (
           SELECT SourceSystem,
                  COUNT(*) AS TotalOrders,
                  SUM(Quantity) AS TotalQty,
                  SUM(Amount) AS TotalAmount
           FROM [ai].[vwExternalOrders]
           WHERE OrderDate >= DATEADD(DAY, -90, GETDATE())
           GROUP BY SourceSystem
       ) src
       LEFT JOIN (
           SELECT SourceSystem,
                  COUNT(*) AS ImportedOrders,
                  SUM(RawQty) AS ImportedQty,
                  SUM(RawAmount) AS ImportedAmount
           FROM [ai].[RawOrderImport]
           WHERE BatchID = @BatchID
           GROUP BY SourceSystem
       ) imp ON src.SourceSystem = imp.SourceSystem;
    ═══════════════════════════════════════════════════════════════════════ */
    -- ═══════════════════════════════════════════════════════════════════════
    -- STEP 5: Logging, cleanup, and lock release
    -- ═══════════════════════════════════════════════════════════════════════
    SET @CurrentStep = 'Step5_Cleanup';
    DROP TABLE IF EXISTS #RawBatch;
    DECLARE @Duration INT = DATEDIFF(MILLISECOND, @StartTime, SYSUTCDATETIME());
    -- Build comprehensive status message
    SET @StatusMsg = @StatusMsg + CONCAT(
        N'Batch ', @BatchID, N': ',
        @ProcessedRows, N'/', @TotalRows, N' rows',
        N' (', @DuplicateCount, N' dupes, ',
        @NegativeCount, N' neg-qty, ',
        @WarningCount, N' warnings, ',
        @ErrorCount, N' errors)',
        N' in ', @Duration, N'ms',
        CASE WHEN @DryRun = 1 THEN N' [DRY RUN]' ELSE N'' END,
        CASE WHEN @SourceFilter IS NOT NULL THEN N' [filter=' + @SourceFilter + N']' ELSE N'' END
    );
    EXEC [ai].[spLogAudit]
        @EventType  = 'IMPORT',
        @ObjectName = 'RawOrderImport',
        @AffectedRows = @ProcessedRows,
        @Message    = @StatusMsg;
    -- TODO: add monitoring alert if @ErrorCount > 0
    -- TODO: also pull TotalRevenue from ai.LegacyFacts for reconciliation
    --       (^^ old note, LegacyFacts was decommissioned in 2024)
    -- TODO: add Prometheus metrics push for batch duration + row count
    -- TODO: integrate with Azure Monitor custom metrics
    -- TODO: consider switching to polybase external table for direct-read
    --       instead of import-then-read pattern (blocked on IT security review)
    IF @ErrorCount > 0
    BEGIN
        DECLARE @ErrMsg NVARCHAR(MAX) = CONCAT(
            N'Import completed with ', @ErrorCount, N' errors. ',
            N'Processed: ', @ProcessedRows, N'/', @TotalRows,
            N' in ', @Duration, N'ms. ',
            N'BatchID: ', @BatchID, N'. ',
            N'Retries: extract=', @ExtractRetry, N', insert=', @InsertRetry, N'. ',
            @StatusMsg
        );
        INSERT INTO [ai].[ErrorLog] (ProcedureName, ErrorNumber, ErrorMessage)
        VALUES ('spImportOrders.Summary', 0, @ErrMsg);
    END;
    -- Release advisory lock
    EXEC sp_releaseapplock @Resource = 'spImportOrders_Lock', @LockOwner = 'Session';
END;
